queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?department_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasDepartments ?child ; p:hasNews_Agencies ?parent . } GROUP BY ?child }
  ?child p:department_name ?department_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :News_Agency } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?department_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasDepartments ?child ; p:hasNews_Agencies ?parent . } GROUP BY ?child }
  ?child p:department_name ?department_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :News_Agency } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?department_name WHERE {
  ?news_agencies_departments a :News_Agencies_Departments .
  ?departments a :Departments .
  ?news_agencies_departments p:hasDepartments ?departments .
  ?news_agencies a :News_Agency .
  ?news_agencies_departments p:hasNews_Agencies ?news_agencies .
  ?news_agencies p:name ?name .
  ?departments p:department_name ?department_name .
} }
}
